   136	/// Store arbitrary blob content under a specific ref/path without touching the working tree.
   137	///
   138	/// This powers `opensession share --git`, which needs explicit ref/path control.
   139	pub fn store_blob_at_ref(
   140	    repo_path: &Path,
   141	    ref_name: &str,
   142	    rel_path: &str,
   143	    body: &[u8],
   144	    message: &str,
   145	) -> Result<ObjectId> {
   146	    let repo = ops::open_repo(repo_path)?;
   147	    let hash_kind = repo.object_hash();
   148	
   149	    let blob = repo.write_blob(body).map_err(gix_err)?.detach();
   150	    let tip = ops::find_ref_tip(&repo, ref_name)?;
   151	    let base_tree_id = match &tip {
   152	        Some(commit_id) => ops::commit_tree_id(&repo, commit_id.detach())?,
   153	        None => ObjectId::empty_tree(hash_kind),
   154	    };
   155	
   156	    let mut editor = repo.edit_tree(base_tree_id).map_err(gix_err)?;
   157	    editor
   158	        .upsert(rel_path, EntryKind::Blob, blob)
   159	        .map_err(gix_err)?;
   160	    let new_tree_id = editor.write().map_err(gix_err)?.detach();
   161	    let parent = tip.map(|id| id.detach());
   162	    ops::create_commit(&repo, ref_name, new_tree_id, parent, message)
   163	}
