   167	    ///
   168	    /// Stores body and metadata blobs plus per-commit index entries:
   169	    /// `v1/index/commits/<sha>/<session_id>.json`.
   170	    pub fn store_session_at_ref(
   171	        &self,
   172	        repo_path: &Path,
   173	        ref_name: &str,
   174	        session_id: &str,
   175	        hail_jsonl: &[u8],
   176	        meta_json: &[u8],
   177	        commit_shas: &[String],
   178	    ) -> Result<StoredSessionRecord> {
   179	        let repo = ops::open_repo(repo_path)?;
   180	        let hash_kind = repo.object_hash();
   181	
   182	        // Write blobs
   183	        let hail_blob = repo.write_blob(hail_jsonl).map_err(gix_err)?.detach();
   184	        let meta_blob = repo.write_blob(meta_json).map_err(gix_err)?.detach();
   185	
   186	        debug!(
   187	            session_id,
   188	            hail_blob = %hail_blob,
   189	            meta_blob = %meta_blob,
   190	            "Wrote session blobs"
   191	        );
   192	
   193	        let prefix = Self::session_prefix(session_id);
   194	        let hail_path = format!("{prefix}.hail.jsonl");
   195	        let meta_path = format!("{prefix}.meta.json");
   196	
   197	        // Determine base tree: existing branch tree or empty tree
   198	        let tip = ops::find_ref_tip(&repo, ref_name)?;
   199	        let base_tree_id = match &tip {
   200	            Some(commit_id) => ops::commit_tree_id(&repo, commit_id.detach())?,
   201	            None => ObjectId::empty_tree(hash_kind),
   202	        };
   203	
   204	        // Build new tree using editor
   205	        let mut editor = repo.edit_tree(base_tree_id).map_err(gix_err)?;
   206	        editor
   207	            .upsert(&hail_path, EntryKind::Blob, hail_blob)
   208	            .map_err(gix_err)?;
   209	        editor
   210	            .upsert(&meta_path, EntryKind::Blob, meta_blob)
   211	            .map_err(gix_err)?;
   212	
   213	        for sha in commit_shas {
   214	            let trimmed = sha.trim();
   215	            if trimmed.is_empty() {
   216	                continue;
   217	            }
   218	            let index_path = Self::commit_index_path(trimmed, session_id);
   219	            let payload = Self::commit_index_payload(session_id, &hail_path, &meta_path);
   220	            let payload_bytes = serde_json::to_vec(&payload)?;
